Game Code
The following code implements the Tetris firmware for the handheld console. It defines the board state, tetromino data, display multiplexing, button handling, collision logic, scoring, audio feedback, rendering, and the main game loop.
#include &lt;STC15.H&gt;
#include &lt;stdint.h&gt;

/* ─────────────────────────────────────────────
   PORT DEFINITIONS
   Adjust these to match your PCB's routing.
   ───────────────────────────────────────────── */
#define ROW_PORT   P0
#define COL_PORT   P2
#define SEG_PORT   P1
#define DIGIT_PORT P3

#define BTN_LEFT   P4_0
#define BTN_RIGHT  P4_1
#define BTN_DOWN   P4_2
#define BTN_ROT    P4_3
#define BTN_PAUSE  P4_4
#define BUZZER     P4_5

#define BOARD_WIDTH  8
#define BOARD_HEIGHT 16

uint8_t board[BOARD_HEIGHT]       = {0};
uint8_t framebuffer[BOARD_HEIGHT] = {0};

const uint16_t PIECES[7][4] = {
    { 0x0F00, 0x2222, 0x00F0, 0x4444 },
    { 0x6600, 0x6600, 0x6600, 0x6600 },
    { 0x0E40, 0x4C40, 0x4E00, 0x4640 },
    { 0x06C0, 0x4620, 0x06C0, 0x4620 },
    { 0x0C60, 0x2640, 0x0C60, 0x2640 },
    { 0x0E20, 0x4C00, 0x8E00, 0x6400 },
    { 0x0E80, 0xC400, 0x2E00, 0x4600 }
};

typedef struct {
    int8_t  x;
    int8_t  y;
    uint8_t type;
    uint8_t rotation;
} Piece;

Piece current;
Piece next;

uint8_t rng_state = 42;
uint8_t current_row   = 0;
uint8_t seg_digits[3] = {0, 0, 0};
uint8_t prev_rot   = 1;
uint8_t prev_pause = 1;
uint8_t score = 0;
uint8_t tick_counter  = 0;
uint8_t drop_interval = 40;
uint8_t first_spawn   = 1;

const uint8_t SEG7[10] = {
    0x3F, 0x06, 0x5B, 0x4F, 0x66,
    0x6D, 0x7D, 0x07, 0x7F, 0x6F
};

void board_clear() {
    uint8_t i;
    for (i = 0; i &lt; BOARD_HEIGHT; i++)
        board[i] = 0;
}

uint8_t board_get(int8_t x, int8_t y) {
    if (x &lt; 0 || x &gt;= BOARD_WIDTH || y &lt; 0 || y &gt;= BOARD_HEIGHT)
        return 1;
    return (board[y] &gt;&gt; (7 - x)) & 1;
}

void board_set(int8_t x, int8_t y, uint8_t val) {
    if (x &lt; 0 || x &gt;= BOARD_WIDTH || y &lt; 0 || y &gt;= BOARD_HEIGHT)
        return;
    if (val)
        board[y] |=  (1 &lt;&lt; (7 - x));
    else
        board[y] &= ~(1 &lt;&lt; (7 - x));
}

uint8_t piece_get(uint16_t mask, uint8_t x, uint8_t y) {
    return (mask &gt;&gt; (15 - (y * 4 + x))) & 1;
}

uint16_t current_mask() {
    return PIECES[current.type][current.rotation];
}

void delay_ms(uint8_t ms) {
    uint8_t i, j;
    while (ms--) {
        for (i = 0; i &lt; 114; i++)
            for (j = 0; j &lt; 1; j++);
    }
}

uint8_t rand8() {
    rng_state = rng_state * 109 + 89;
    return rng_state;
}

void timer0_isr() interrupt 1 {
    TH0 = 0xFC;
    TL0 = 0x66;

    if (current_row &lt; 16) {
        ROW_PORT = 0xFF;
        COL_PORT = ~framebuffer[current_row];
        ROW_PORT = ~(1 &lt;&lt; (current_row % 8));
    } else {
        uint8_t digit = current_row - 16;
        DIGIT_PORT = 0x00;
        SEG_PORT   = SEG7[seg_digits[digit]];
        DIGIT_PORT = (1 &lt;&lt; digit);
    }

    current_row = (current_row + 1) % 19;
}

void timer0_init() {
    TMOD &= 0xF0;
    TH0 = 0xFC;
    TL0 = 0x66;
    ET0 = 1;
    TR0 = 1;
    EA  = 1;
}

uint8_t button_pressed(bit btn_pin) {
    if (btn_pin == 0) {
        delay_ms(15);
        if (btn_pin == 0)
            return 1;
    }
    return 0;
}

uint8_t button_edge(bit btn_pin, uint8_t *prev) {
    uint8_t cur = (btn_pin == 0) ? 0 : 1;
    uint8_t pressed = (*prev == 1 && cur == 0);
    *prev = cur;
    return pressed;
}

uint8_t collision(int8_t dx, int8_t dy, uint8_t new_rotation) {
    uint8_t x, y;
    uint16_t mask = PIECES[current.type][new_rotation];

    for (y = 0; y &lt; 4; y++) {
        for (x = 0; x &lt; 4; x++) {
            if (!piece_get(mask, x, y))
                continue;
            if (board_get(current.x + x + dx,
                          current.y + y + dy))
                return 1;
        }
    }
    return 0;
}

void move_piece(int8_t dx, int8_t dy) {
    if (!collision(dx, dy, current.rotation)) {
        current.x += dx;
        current.y += dy;
    }
}

void rotate_piece() {
    uint8_t new_rot = (current.rotation + 1) % 4;

    if (!collision(0, 0, new_rot)) {
        current.rotation = new_rot;
    } else if (!collision(-1, 0, new_rot)) {
        current.rotation = new_rot;
        current.x -= 1;
    } else if (!collision(1, 0, new_rot)) {
        current.rotation = new_rot;
        current.x += 1;
    }
}

void lock_piece() {
    uint8_t x, y;
    uint16_t mask = current_mask();

    for (y = 0; y &lt; 4; y++) {
        for (x = 0; x &lt; 4; x++) {
            if (piece_get(mask, x, y))
                board_set(current.x + x, current.y + y, 1);
        }
    }
}

void update_7seg(uint8_t val) {
    seg_digits[0] = val / 100;
    seg_digits[1] = (val / 10) % 10;
    seg_digits[2] = val % 10;
}

void clear_lines() {
    int8_t y;
    uint8_t lines = 0;

    for (y = BOARD_HEIGHT - 1; y &gt;= 0; y--) {
        if (board[y] == 0xFF) {
            int8_t yy;
            for (yy = y; yy &gt; 0; yy--)
                board[yy] = board[yy - 1];
            board[0] = 0x00;
            lines++;
            y++;
        }
    }

    const uint8_t points[5] = {0, 1, 3, 5, 8};
    if (lines &gt; 0 && lines &lt;= 4)
        score += points[lines];
    if (score &gt; 99) score = 99;

    update_7seg(score);
}

void buzzer_tone(uint16_t freq_hz, uint16_t duration_ms) {
    uint16_t half_period_us = 500000UL / freq_hz;
    uint16_t cycles = (uint32_t)duration_ms * freq_hz / 1000;
    uint16_t i;

    for (i = 0; i &lt; cycles; i++) {
        BUZZER = 0;
        uint16_t d = half_period_us / 10;
        while (d--);
        BUZZER = 1;
        d = half_period_us / 10;
        while (d--);
    }
    BUZZER = 1;
}

void buzzer_click()    { buzzer_tone(1000,  20);  }
void buzzer_line()     { buzzer_tone(880,   80);  }
void buzzer_tetris()   { buzzer_tone(1320,  200); }
void buzzer_gameover() { buzzer_tone(220,   800); }

void spawn_piece() {
    if (first_spawn) {
        rng_state ^= TL0;
        first_spawn = 0;
    }

    current       = next;
    current.x     = 2;
    current.y     = 0;

    next.type     = rand8() % 7;
    next.rotation = 0;
}

void render() {
    uint8_t x, y;
    uint16_t mask = current_mask();

    for (y = 0; y &lt; BOARD_HEIGHT; y++)
        framebuffer[y] = board[y];

    for (y = 0; y &lt; 4; y++) {
        for (x = 0; x &lt; 4; x++) {
            if (piece_get(mask, x, y)) {
                int8_t bx = current.x + x;
                int8_t by = current.y + y;
                if (by &gt;= 0 && by &lt; BOARD_HEIGHT &&
                    bx &gt;= 0 && bx &lt; BOARD_WIDTH)
                    framebuffer[by] |= (1 &lt;&lt; (7 - bx));
            }
        }
    }
}

void update_speed() {
    if      (score &gt;= 50) drop_interval = 4;
    else if (score &gt;= 30) drop_interval = 8;
    else if (score &gt;= 20) drop_interval = 16;
    else if (score &gt;= 10) drop_interval = 24;
    else                  drop_interval = 40;
}

void pause_game() {
    while (button_edge(BTN_PAUSE, &prev_pause) == 0) {
        delay_ms(16);
    }
}

void game_over() {
    board_clear();
    score = 0;
    first_spawn = 1;
    update_7seg(0);
    delay_ms(1000);

    next.type = rand8() % 7;
    next.rotation = 0;
    spawn_piece();
}

void game_init() {
    board_clear();
    score         = 0;
    tick_counter  = 0;
    drop_interval = 40;
    first_spawn   = 1;
    prev_rot      = 1;
    prev_pause    = 1;
    rng_state     = 73;

    next.type     = rand8() % 7;
    next.rotation = 0;
    spawn_piece();
    update_7seg(0);
}

void main() {
    timer0_init();
    game_init();

    while (1) {
        if (button_pressed(BTN_LEFT))
            move_piece(-1, 0);

        if (button_pressed(BTN_RIGHT))
            move_piece( 1, 0);

        if (button_pressed(BTN_DOWN))
            move_piece( 0, 1);

        if (button_edge(BTN_ROT, &prev_rot))
            rotate_piece();

        if (button_edge(BTN_PAUSE, &prev_pause))
            pause_game();

        if (tick_counter &gt;= drop_interval) {
            tick_counter = 0;

            if (!collision(0, 1, current.rotation)) {
                current.y++;
            } else {
                lock_piece();
                buzzer_click();
                clear_lines();
                update_speed();
                spawn_piece();

                if (collision(0, 0, current.rotation))
                    game_over();
            }
        }

        render();
        delay_ms(16);
        tick_counter++;
    }
}




